/**
 * User notification preferences model.
 *
 * Controls how and when users receive notifications.
 * Currently supports email preferences; designed to be extended
 * with additional channels (SMS, webhook, in-app) in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency. Controls batching behavior:
 * - 'immediate': send as soon as the event occurs
 * - 'daily_digest': batch into a daily summary
 * - 'weekly_digest': batch into a weekly summary
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master toggle for all email notifications */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to */
  subscribedCategories: NotificationType[];
}

/**
 * User notification preferences.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 */
export interface CreatePreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
}

/**
 * Input for updating user preferences.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * Default email preferences for new users.
 * All categories enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences, EmailPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as EmailPreferences,
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and a method
 * to check whether a notification should be delivered based on
 * the user's current settings.
 *
 * Depends on:
 * - PreferencesRepository for data access
 * - NotificationType from notification model
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import type {
  UserPreferences,
  CreatePreferencesInput,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Create preferences for a user. Merges provided settings with defaults.
   * @throws Error if preferences already exist for this user
   */
  createPreferences(input: CreatePreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(input.userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${input.userId}`);
    }

    const now = new Date();
    const emailPrefs = {
      ...DEFAULT_EMAIL_PREFERENCES,
      ...(input.email ?? {}),
    };

    // If subscribedCategories was provided, use it as-is; otherwise keep the default
    if (input.email?.subscribedCategories) {
      emailPrefs.subscribedCategories = input.email.subscribedCategories;
    }

    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      email: emailPrefs,
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
    return preferences;
  }

  /**
   * Get preferences for a user. Returns undefined if not set.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createPreferences({ userId });
  }

  /**
   * Update preferences for a user.
   * @throws Error if preferences do not exist for this user
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }

    const updatedEmail = input.email
      ? { ...existing.email, ...input.email }
      : existing.email;

    if (input.email?.subscribedCategories) {
      updatedEmail.subscribedCategories = input.email.subscribedCategories;
    }

    const updated: UserPreferences = {
      ...existing,
      email: updatedEmail,
      updatedAt: new Date(),
    };

    this.preferencesRepository.update(existing.id, updated);
    this.logger.info(`Updated preferences for user ${userId}`);
    return updated;
  }

  /**
   * Delete preferences for a user.
   * @throws Error if preferences do not exist for this user
   */
  deletePreferences(userId: string): void {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      throw new Error(`Preferences not found for user: ${userId}`);
    }
    this.preferencesRepository.delete(existing.id);
    this.logger.info(`Deleted preferences for user ${userId}`);
  }

  /**
   * Check if a notification should be delivered to a user on a given channel.
   *
   * Returns true if:
   * - No preferences exist for the user (default: allow all)
   * - The channel is enabled AND the notification type is in subscribed categories
   *
   * Currently only 'email' channel is supported.
   */
  shouldSendNotification(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences stored — default to sending
    if (!preferences) {
      return true;
    }

    if (channel === 'email') {
      if (!preferences.email.enabled) {
        this.logger.info(`Email notifications disabled for user ${userId}`);
        return false;
      }
      if (preferences.email.frequency === 'none') {
        this.logger.info(`Email frequency set to none for user ${userId}`);
        return false;
      }
      if (!preferences.email.subscribedCategories.includes(notificationType)) {
        this.logger.info(
          `User ${userId} not subscribed to ${notificationType} emails`,
        );
        return false;
      }
      return true;
    }

    // For unsupported channels, default to sending
    return true;
  }
}

